// Code: splitar o texto grande em partes menores
// coloca este node ANTES do AI Agent

// pega o texto que veio do extractor
const full = $input.item.json.data || $input.item.json.text || '';
// tamanho máximo por parte (ajuste se precisar)
const MAX_CHARS = 8000;

const out = [];

for (let i = 0; i < full.length; i += MAX_CHARS) {
  out.push({
    json: {
      // pedaço que o agente vai processar
      data: full.slice(i, i + MAX_CHARS),
      // carrega o documento inteiro junto (pra validar no fim se quiser)
      original: full,
      // índice do pedaço (só pra debug)
      part: Math.floor(i / MAX_CHARS) + 1,
    },
  });
}

return out;

// vamos processar TODOS os itens que vieram do AI Agent
const items = $input.all();
const out = [];

for (const item of items) {
  const raw = item.json.output;
  if (!raw) {
    out.push({
      json: {
        debug: 'Sem campo output vindo do AI Agent neste item',
        received: item.json,
      },
    });
    continue;
  }

  // limpar ```json
  let text = raw.trim();
  if (text.startsWith('```')) {
    text = text.replace(/```(json)?/g, '').trim();
  }

  // achar "chunks"
  const chunksKeyIndex = text.indexOf('"chunks"');
  if (chunksKeyIndex === -1) {
    out.push({
      json: {
        debug: 'Output não contém "chunks" neste item',
        raw: text,
      },
    });
    continue;
  }

  const bracketStart = text.indexOf('[', chunksKeyIndex);
  if (bracketStart === -1) {
    out.push({
      json: {
        debug: 'Não encontrei "[" depois de "chunks" neste item',
        raw: text,
      },
    });
    continue;
  }

  // varrer objetos completos
  const objs = [];
  let i = bracketStart + 1;
  const len = text.length;
  let braceCount = 0;
  let objStart = -1;

  while (i < len) {
    const ch = text[i];

    if (ch === '{') {
      if (braceCount === 0) objStart = i;
      braceCount++;
    } else if (ch === '}') {
      braceCount--;
      if (braceCount === 0 && objStart !== -1) {
        const objStr = text.slice(objStart, i + 1).trim();
        objs.push(objStr);
        objStart = -1;
      }
    } else if (ch === ']' && braceCount === 0) {
      // fim do array de chunks
      break;
    }

    i++;
  }

  if (!objs.length) {
    out.push({
      json: {
        debug: 'Nenhum chunk completo encontrado neste item',
        raw: text,
      },
    });
    continue;
  }

  // parse e explode
  const chunks = [];
  for (const o of objs) {
    try {
      // 1) tira caracteres nulos do PDF
      // 2) tira vírgula sobrando no final
      const cleanObj = o
        .replace(/\u0000/g, '')
        .replace(/},\s*$/, '}');

      const parsed = JSON.parse(cleanObj);
      chunks.push(parsed);
    } catch (err) {
      // se algum vier quebrado, pula
    }
  }

  // agora cada chunk vira 1 item n8n
  for (let idx = 0; idx < chunks.length; idx++) {
    const c = chunks[idx] || {};
    const textChunk = (c.text || '').replace(/\u0000/g, '');
    out.push({
      json: {
        text: textChunk,
        metadata: {
          chunkNumber: idx + 1,
          totalChunks: chunks.length,
          chunkSize: textChunk.length,
          chunkingMethod: 'agentic-gpt',
          topic: c.topic || `Section ${idx + 1}`,
        },
      },
    });
  }
}

return out;
